        xGm_.SetGlobalBuffer((__gm__ float*)x, static_cast<uint32_t>(totalRows_ * inLen_));
        yGm_.SetGlobalBuffer((__gm__ float*)y, static_cast<uint32_t>(totalRows_ * outLen_));

        pipe_.InitBuffer(tmpQueue_, 1, sizeof(float));
